    private static readonly Dictionary<string, FontAsset> s_sdfFontAssets = new(StringComparer.OrdinalIgnoreCase);
    private static readonly Dictionary<string, string> s_fontResourcePaths = new(StringComparer.OrdinalIgnoreCase)
    {
        ["Press Start 2P"] = "BoomHudFonts/PressStart2P-Regular",
        ["lucide"] = "BoomHudFonts/lucide"
    };
